import {
  Flex,
  Text,
  Button,
  Image,
  Box,
  Input,
  InputGroup,
  InputLeftElement,
} from "@chakra-ui/react";
import { FaSearch } from "react-icons/fa";
import teacher from "../../asset/A.png";
import { useNavigate } from "react-router-dom";

const Section1 = () => {
  const navigate = useNavigate();

  return (
    <Flex
      align="center"
      justify="space-between"
      py={20}
      px={5}
      gap={10}
      direction={{ base: "column", md: "row" }}
    >
      {/* LEFT */}
      <Box
        maxW="500px"
        bg="white"
        p={8}
        borderRadius="lg"
        boxShadow="lg"
      >
        <Text fontSize={{ base: "2xl", md: "3xl" }} fontWeight="bold" mb={4}>
          Learn without limits
        </Text>

        <Text color="gray.600" mb={6}>
          Build skills with courses from top instructors. Learn anything,
          anytime, anywhere with <b>SRM</b>.
        </Text>

        {/* SEARCH */}
        <InputGroup mb={6}>
          <InputLeftElement pointerEvents="none">
            <FaSearch color="gray" />
          </InputLeftElement>

          <Input
            placeholder="What do you want to learn?"
            borderRadius="999px"
            bg="#f7f9fa"
            _focus={{ bg: "white", borderColor: "#A435F0" }}
          />
        </InputGroup>

        {/* BUTTONS */}
        <Flex gap={4} direction={{ base: "column", sm: "row" }}>
          <Button
            bg="#A435F0"
            color="white"
            _hover={{ bg: "#8710d8" }}
            onClick={() => navigate("/signup")}
          >
            Get started
          </Button>

          <Button
            variant="outline"
            onClick={() => navigate("/login")}
          >
            Log in
          </Button>
        </Flex>
      </Box>

      {/* RIGHT IMAGE */}
      <Box
        display={{ base: "none", md: "block" }}
        maxW="500px"
      >
        <Image
          src={teacher}
          alt="learning"
          borderRadius="lg"
        />
      </Box>
    </Flex>
  );
};

export default Section1;
